import java.util.Scanner;

public class SecureBufferCopy {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter your name: ");
        String name = scanner.nextLine();

        // Limiting the buffer size to prevent buffer overflow
        char[] buffer = new char[Math.min(name.length(), 10)];

        // Copy characters from name to buffer with bounds checking
        for (int i = 0; i < buffer.length; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Buffer contents: ");
        for (char ch : buffer) {
            System.out.print(ch);
        }
    }
}

